const currencyFormatter = {
  format: async (amount, currency = 'INR') => {
    try {
      if (typeof amount !== 'number') {
        throw new Error('Invalid amount. Amount must be a number.');
      }

      let locale;
      let currencyCode;

      switch (currency.toUpperCase()) {
        case 'INR':
          locale = 'en-IN';
          currencyCode = 'INR';
          break;
        case 'USD':
          locale = 'en-US';
          currencyCode = 'USD';
          break;
        default:
          throw new Error('Unsupported currency. Supported currencies are INR and USD.');
      }

      const formattedAmount = new Intl.NumberFormat(locale, {
        style: 'currency',
        currency: currencyCode,
      }).format(amount);

      return formattedAmount;
    } catch (error) {
      throw error;
    }
  },
};

module.exports = currencyFormatter;

